function solve(nums, edges) {
    const n = nums.length;
    const adj = Array(n).fill(0).map(() => []);
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let count = 0;

    // Iterate through all non-empty subsets (represented by a bitmask from 1 to 2^n - 1)
    const totalSubsets = 1 << n;
    for (let mask = 1; mask < totalSubsets; mask++) {
        const subset = [];
        let sum = 0;
        for (let i = 0; i < n; i++) {
            if ((mask >> i) & 1) {
                subset.push(i);
                sum += nums[i];
            }
