        // Check condition 2: Sum of values is even
        if (sum % 2 !== 0) {
            continue;
        }

        // Check condition 1: Induced subgraph is connected
        if (subset.length === 0) continue; // Should not happen due to mask starting at 1

        // Check connectivity using BFS/DFS starting from the first node in the subset
        const startNode = subset[0];
        const visited = new Set();
        const queue = [startNode];
        visited.add(startNode);
        let visitedCount = 0;

        while (queue.length > 0) {
            const u = queue.shift();
            visitedCount++;

            for (const v of adj[u]) {
                // Check if v is in the subset AND not yet visited
                if (((mask >> v) & 1) && !visited.has(v)) {
                    visited.add(v);
                    queue.push(v);
                }
            }
        }

        // The induced subgraph is connected if we visited exactly |subset| nodes
        if (visitedCount === subset.length) {
            count++;
        }
    }

    return count;
}

